import json, os

base = "C:/Users/Peter/pkang6689-pixel.github.io/content_data/APLessons/AP Physics 2"

def write_quiz(unit, lesson, title, questions, subdir=None):
    data = {
        "unit": unit,
        "lesson_number": lesson,
        "title": title,
        "course": "AP Physics 2",
        "quiz_questions": questions
    }
    if subdir:
        path = os.path.join(base, subdir, f"Lesson{lesson}_Quiz.json")
    else:
        path = os.path.join(base, f"Lesson{lesson}_Quiz.json")
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    print(f"Wrote {path} ({len(questions)} questions)")

def q(num, text, opts, ci, expl):
    options = []
    for i, opt in enumerate(opts):
        options.append({"text": opt, "is_correct": i == ci, "data_i18n": None})
    return {
        "question_number": num,
        "question_text": text,
        "attempted": 2,
        "data_i18n": None,
        "options": options,
        "explanation": expl
    }

